    /**
     * @throws Exception
     * @return bool
     */
    public function validate(): bool {
        return Capability::validateAction($this->action)
        || Capability::validateIframeAllow($this->iframeAllow)
        || Capability::validateMIMETypes($this->mimeTypes)
        || Capability::validateMultiple($this->multiple)
        || Capability::validatePath($this->path);
    }

    /**
     * @return stdClass
     * @throws Exception
     */
    public function to(): stdClass  {
        $out = new stdClass();
        $out->{'action'} = $this->toAction();
        $out->{'iframeAllow'} = $this->toIframeAllow();
        $out->{'mimeTypes'} = $this->toMIMETypes();
        $out->{'multiple'} = $this->toMultiple();
        $out->{'path'} = $this->toPath();
        return $out;
    }

    /**
     * @param stdClass $obj
     * @return Capability
     * @throws Exception
     */
    public static function from(stdClass $obj): Capability {
        return new Capability(
         Capability::fromAction($obj->{'action'})
        ,Capability::fromIframeAllow($obj->{'iframeAllow'})
        ,Capability::fromMIMETypes($obj->{'mimeTypes'})
        ,Capability::fromMultiple($obj->{'multiple'})
        ,Capability::fromPath($obj->{'path'})
        );
    }

